class Solution:
    def punishmentNumber(self, n: int) -> int:
        def can_partition(s: str, target: int) -> bool:
            if not s:
                return False
            if s == str(target):
                return True
            for i in range(1, len(s)):
                left = int(s[:i])
                if left > target:
                    continue
                if can_partition(s[i:], target - left):
                    return True
            return False

        total = 0
        for i in range(1, n + 1):
            square = i * i
            square_str = str(square)
            if can_partition(square_str, i):
                total += square
        return total
